SELECT /* base.sy :: SyI18n :: selectList */ i.* , ste.site_nm AS site_nm , cd_is.code_label AS i18n_scope_cd_nm FROM sy_i18n i LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN sy_code cd_is ON cd_is.code_grp = 'I18N_SCOPE' AND cd_is.code_value = i.i18n_scope_cd
ORDER BY i.i18n_id ASC ORDER BY i.i18n_id DESC ORDER BY i.reg_date ASC ORDER BY i.reg_date DESC ORDER BY i.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.sy :: SyI18n :: selectPageList */ i.* , ste.site_nm AS site_nm , cd_is.code_label AS i18n_scope_cd_nm FROM sy_i18n i LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN sy_code cd_is ON cd_is.code_grp = 'I18N_SCOPE' AND cd_is.code_value = i.i18n_scope_cd
ORDER BY i.i18n_id ASC ORDER BY i.i18n_id DESC ORDER BY i.reg_date ASC ORDER BY i.reg_date DESC ORDER BY i.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE sy_i18n /* base.sy :: SyI18n :: updateSelective */
site_id = #{siteId}, i18n_key = #{i18nKey}, i18n_desc = #{i18nDesc}, i18n_scope_cd = #{i18nScopeCd}, i18n_category = #{i18nCategory}, sort_ord = #{sortOrd}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE i18n_id = #{i18nId}
